import { execSync } from "child_process";
import fs from "fs";
function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;for(let a=0;a<5;a++){try{const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'dfn '+n,branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));const r=execSync('curl -s -w "\\nHTTP:%{http_code}" -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8',maxBuffer:80000000});if(/HTTP:20[01]/.test(r))return true;}catch(e){}execSync('sleep 3');}return false;}
let out='';const L=s=>{out+=s+'\n';console.log(s);};
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const PHP=Buffer.from("",'base64').toString('utf8');
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k -w "\\nHTTP:%{http_code}" '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k -w "\\nHTTP:%{http_code}" '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'')+'\nHTTP:ERR';}return{code:(r.match(/HTTP:(\S+)$/)||[])[1]||'?',body:r.replace(/\nHTTP:\S+$/,'')};}
function sh(c){try{return execSync(c,{encoding:'utf8',maxBuffer:30000000});}catch(e){return (e.stdout||'')+'[ERR]';}}
(async()=>{const R={};let id=0;try{
  const list=api('GET','/wp-json/code-snippets/v1/snippets?limit=300');
  let ex=null;try{ex=JSON.parse(list.body).find(s=>/Deploy Functions/i.test(s.name));}catch(e){}
  const payload={name:'Petshop Deploy Functions v1',desc:'token',code:PHP,scope:'front-end',active:true,priority:10};
  const c=ex?api('POST','/wp-json/code-snippets/v1/snippets/'+ex.id,payload):api('POST','/wp-json/code-snippets/v1/snippets',payload);
  try{id=JSON.parse(c.body).id;}catch(e){}
  L('deploy snippet id='+id); execSync('sleep 2');
  const r=sh('curl -s -k --max-time 50 "'+BASE+'/?ps_deployfn=1&token=cmplz_6680aa2a42151d54fa8d64ec"');
  L('=== DEPLOY REZULTATAS ===');L(r.slice(0,1500));R.deploy=r.slice(0,2000);
  let ok=false;try{ok=JSON.parse(r).DEPLOY_OK;}catch(e){}
  L('DEPLOY_OK='+ok);
  // deaktyvuojam deploy snippet nedelsiant
  if(id){api('POST','/wp-json/code-snippets/v1/snippets/'+id+'/deactivate',{});L('deploy snippet deakt');}
  // HOMEPAGE + admin sveikatos patikra (fatal detection)
  execSync('sleep 2');
  const home=sh('curl -s -k -o /dev/null -w "%{http_code}" --max-time 30 "'+BASE+'/"');
  L('homepage HTTP: '+home);
  const shop=sh('curl -s -k -o /dev/null -w "%{http_code}" --max-time 30 "'+BASE+'/parduotuve/"');
  L('parduotuve HTTP: '+shop);
  // ar yra fatal error tekstas?
  const homeBody=sh('curl -s -k --max-time 30 "'+BASE+'/" | head -c 3000');
  const hasFatal=/Fatal error|Parse error|There has been a critical error/i.test(homeBody);
  L('fatal error homepage: '+hasFatal);
  R.health={home,shop,hasFatal};
  if(hasFatal||home.indexOf('200')!==0){
    L('!!! SVEIKATOS PATIKRA NEPRAEJO - reikia ROLLBACK is .bak !!!');
    R.NEEDS_ROLLBACK=true;
  } else { L('SVEIKATA OK - failas veikia'); R.NEEDS_ROLLBACK=false; }
}catch(e){L('!!! '+(e&&e.stack?e.stack:e));}
finally{putText('deploy_functions_result.json',JSON.stringify(R,null,2));putText('_run34_log.txt',out);}})();
